mapper.select:
SELECT
ab.id, ab.user_id, ab.user_name, ab.dept_id, ab.violate_count, ab.status,
ab.reason, ab.expire_time, ab.remark, ab.enabled, ab.create_time, ab.update_time
FROM act_blacklist ab
WHERE ab.enabled = '1'

    AND ab.user_id = #{req.userId}


    AND ab.user_name LIKE CONCAT('%', #{req.userName}, '%')


    AND ab.status = #{req.status}


    ${req.dataScopeSql}

ORDER BY ab.create_time DESC, ab.id DESC
